import { useEffect, useState } from "react";

const AdminOrders = () => {
  const [orders, setOrders] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/api/admin/orders")
      .then(res => res.json())
      .then(setOrders);
  }, []);

  return (
    <div>
      <h2>Orders</h2>
      {orders.map(o => (
        <p key={o.id}>RM {o.total_amount} - {o.payment_status}</p>
      ))}
    </div>
  );
};

export default AdminOrders;
